import fs from "node:fs";

const files = [
  "auth.rs", "cleanup_queue.rs", "clerk_users.rs", "cli_auth.rs", "outbox.rs",
  "projection_read_models.rs", "repo_change_notifications.rs", "repo_collaboration.rs",
  "repo_lifecycle.rs", "repo_mutation.rs", "repo_reads.rs", "request_merges.rs",
  "requests.rs", "visibility_changes.rs"
].map((name) => `crates/scope-core/src/db/${name}`);

function matchingBrace(source, open) {
  let depth = 0;
  let state = "code";
  for (let i = open; i < source.length; i++) {
    const c = source[i], n = source[i + 1];
    if (state === "line") {
      if (c === "\n") state = "code";
      continue;
    }
    if (state === "block") {
      if (c === "*" && n === "/") { state = "code"; i++; }
      continue;
    }
    if (state === "string") {
      if (c === "\\") { i++; continue; }
      if (c === '"') state = "code";
      continue;
    }
    if (state === "char") {
      if (c === "\\") { i++; continue; }
      if (c === "'") state = "code";
      continue;
    }
    if (c === "/" && n === "/") { state = "line"; i++; continue; }
    if (c === "/" && n === "*") { state = "block"; i++; continue; }
    if (c === '"') { state = "string"; continue; }
    if (c === "'") { state = "char"; continue; }
    if (c === "{") depth++;
    if (c === "}" && --depth === 0) return i;
  }
  throw new Error("unmatched wrapper brace");
}

for (const path of files) {
  let source = fs.readFileSync(path, "utf8");
  const marker = "run_api_db_on(runtime, async move {";
  const methods = new Set();
  let starts = [];
  for (let from = 0; ; ) {
    const start = source.indexOf(marker, from);
    if (start < 0) break;
    starts.push(start);
    const prefix = source.slice(0, start);
    const match = [...prefix.matchAll(/(?:pub )?fn ([a-zA-Z0-9_]+)/g)].at(-1);
    if (match) methods.add(match[1]);
    from = start + marker.length;
  }
  for (const start of starts.reverse()) {
    const open = start + marker.length - 1;
    const close = matchingBrace(source, open);
    let end = close + 1;
    while (/\s/.test(source[end]) && source[end] !== "\n") end++;
    if (source[end] !== ")") throw new Error(`wrapper close missing in ${path}`);
    end++;
    let body = source.slice(open + 1, close);
    if (body.startsWith("\n")) body = body.slice(1);
    body = body.replace(/^ {4}/gm, "");
    source = source.slice(0, start) + body.trimEnd() + source.slice(end);
  }

  source = source
    .replace(/let MetadataStoreInner::Postgres \{ db, runtime \} = self\.inner\.as_ref\(\);\n\s*let db = Arc::clone\(db\);/g, "let db = Arc::clone(&self.db);")
    .replace(/let MetadataStoreInner::Postgres \{ db, runtime \} = store\.inner\.as_ref\(\);\n\s*let db = Arc::clone\(db\);/g, "let db = Arc::clone(&store.db);")
    .replace(/\bMetadataStoreInner,?\s*/g, "")
    .replace(/\brun_api_db_on,?\s*/g, "");

  for (const method of methods) {
    source = source.replace(
      new RegExp(`(pub\\s+)fn\\s+${method}\\b`),
      `$1async fn ${method}`
    );
    source = source.replace(
      new RegExp(`(^|\\n)fn\\s+${method}\\b`),
      `$1async fn ${method}`
    );
  }
  fs.writeFileSync(path, source);
}

