    if (state === "string") { if (c === "\\") i++; else if (c === '"') state = "code"; continue; }
    if (state === "char") { if (c === "\\") i++; else if (c === "'") state = "code"; continue; }
    if (c === "/" && n === "/") { state = "line"; i++; continue; }
    if (c === "/" && n === "*") { state = "block"; i++; continue; }
    if (c === '"') { state = "string"; continue; }
