#!/usr/bin/env node
import { spawn } from 'node:child_process';
import { mkdir, mkdtemp, rm, writeFile } from 'node:fs/promises';
import { join, resolve } from 'node:path';
import { performance } from 'node:perf_hooks';

const apiUrl = (process.env.SCOPE_BENCH_API_URL || 'http://localhost:8080').replace(/\/$/, '');
const token = process.env.SCOPE_BENCH_AUTH_TOKEN || '';
const samples = positiveInt('SCOPE_BENCH_SAMPLES', 12);
const warmup = positiveInt('SCOPE_BENCH_WARMUP', 2);
const concurrency = positiveInt('SCOPE_BENCH_CONCURRENCY', 6);
const timeoutMs = positiveInt('SCOPE_BENCH_TIMEOUT_MS', 15_000);
const outputRoot = resolve(
  process.env.SCOPE_BENCH_OUTPUT_DIR || '.tmp/bench/phase0',
);
const owner = normalizeHandle(
  process.env.SCOPE_BENCH_OWNER ||
    process.env.SCOPE_DEV_USER_HANDLE ||
    process.env.SCOPE_DEV_USER_EMAIL?.split('@')[0] ||
    'dev',
);

await main();

async function main() {
  await expectReady();
  const cases = benchmarkCases();
  const results = [];
  for (const benchCase of cases) {
    process.stdout.write(`running ${benchCase.name}... `);
    const result = await runCase(benchCase);
    results.push(result);
    process.stdout.write(`${result.ok ? 'ok' : 'failed'}\n`);
  }

  const generatedAt = new Date();
  const report = {
    version: 2,
    phase: 'phase-0',
    generatedAt: generatedAt.toISOString(),
    apiUrl,
    owner,
    config: { samples, warmup, concurrency, timeoutMs, authenticated: Boolean(token) },
    environment: { node: process.version, platform: process.platform, arch: process.arch },
    cases: results,
    skipped: token
      ? []
      : [{ name: 'authenticated reads and receive-pack', reason: 'SCOPE_BENCH_AUTH_TOKEN is not set' }],
  };
  const outputDir = join(outputRoot, generatedAt.toISOString().replaceAll(':', '-'));
  await mkdir(outputDir, { recursive: true });
  const jsonPath = join(outputDir, 'results.json');
  const markdownPath = join(outputDir, 'summary.md');
  await writeFile(jsonPath, `${JSON.stringify(report, null, 2)}\n`);
  await writeFile(markdownPath, markdown(report));
  console.log(`results: ${jsonPath}\nsummary: ${markdownPath}`);
  if (results.some((result) => !result.ok)) process.exitCode = 1;
}

function benchmarkCases() {
  const publicBase = `/v1/repos/${segment(owner)}/public-demo`;
  const updateBase = `/v1/repos/${segment(owner)}/update-demo`;
  const cases = [
    httpCase('repo summary', publicBase),
    httpCase('repo files', `${publicBase}/files`),
    httpCase('projection preview', `${publicBase}/projection-preview?audience=public&source=live`),
    httpCase('commit history', `${publicBase}/commits?audience=public`),
    commandCase('git ls-remote', [
      'ls-remote',
      `${apiUrl}/git/public/${owner}/public-demo`,
    ]),
  ];
  if (token) {
    cases.push(
      httpCase('authenticated repo list', '/v1/repos', true),
      httpCase('private projection preview', `${updateBase}/projection-preview?audience=private&source=live`, true),
      { name: 'git receive-pack first push', kind: 'push', burst: false },
    );
  }
  return cases;
}

function httpCase(name, path, auth = false) {
  return { name, kind: 'http', url: `${apiUrl}${path}`, auth, burst: true };
}

function commandCase(name, args) {
  return { name, kind: 'command', command: 'git', args, burst: false };
}

async function runCase(benchCase) {
  const run = () => runSample(benchCase);
  const warmupSamples = await sequential(warmup, run);
  const sequentialSamples = await sequential(samples, run);
  const burstSamples = benchCase.burst
    ? (await sequential(samples, () =>
        Promise.all(Array.from({ length: concurrency }, run)),
      )).flat()
    : [];
  const all = [...warmupSamples, ...sequentialSamples, ...burstSamples];
  return {
    name: benchCase.name,
    kind: benchCase.kind,
    ok: all.every((sample) => sample.ok),
    warmup: summarize(warmupSamples),
    sequential: summarize(sequentialSamples),
    burst: benchCase.burst ? summarize(burstSamples) : null,
    failures: all.filter((sample) => !sample.ok).slice(0, 5),
  };
}

async function sequential(count, operation) {
  const values = [];
  for (let index = 0; index < count; index += 1) values.push(await operation());
  return values;
}

function runSample(benchCase) {
  if (benchCase.kind === 'http') return sampleFetch(benchCase);
  if (benchCase.kind === 'push') return samplePush();
  return sampleCommand(benchCase.command, benchCase.args);
}

async function sampleFetch(benchCase) {
  const started = performance.now();
  try {
    const headers = { accept: 'application/json' };
    if (benchCase.auth) headers.authorization = `Bearer ${token}`;
    const response = await fetch(benchCase.url, {
      headers,
      signal: AbortSignal.timeout(timeoutMs),
    });
    const bytes = (await response.arrayBuffer()).byteLength;
    return sample(response.ok, started, response.status, bytes, response.ok ? null : `HTTP ${response.status}`);
  } catch (error) {
    return sample(false, started, null, 0, message(error));
  }
}

async function samplePush() {
  const started = performance.now();
  let fixture;
  try {
    fixture = await createPushFixture();
    const result = await sampleCommand(
      'git',
      ['push', fixture.remoteUrl, `HEAD:${fixture.branch}`],
      fixture.dir,
      gitAuthEnv(fixture.remoteUrl, fixture.pushToken),
    );
    return { ...result, durationMs: performance.now() - started };
  } catch (error) {
    return sample(false, started, null, 0, message(error));
  } finally {
    if (fixture) await cleanupFixture(fixture);
  }
}

async function createPushFixture() {
  const created = await apiJson('/v1/repos', {
    method: 'POST',
    body: { name: `bench-${Date.now()}-${Math.random().toString(16).slice(2)}`, visibility: 'Public' },
  });
  const fixture = {
    owner: created.repo.owner_handle,
    repo: created.repo.name,
    remoteUrl: created.init.git_remote_url,
    branch: created.init.push_branch || 'main',
    pushToken: created.init.push_token.secret,
    dir: await mkdtemp(join(outputRoot, 'push-')),
  };
  await checkedGit(['init'], fixture.dir);
  await checkedGit(['symbolic-ref', 'HEAD', 'refs/heads/main'], fixture.dir);
  await checkedGit(['config', 'user.email', 'bench@scope.local'], fixture.dir);
  await checkedGit(['config', 'user.name', 'Scope Bench'], fixture.dir);
  await writeFile(join(fixture.dir, 'README.md'), '# Scope benchmark\n');
  await checkedGit(['add', '--all'], fixture.dir);
  await checkedGit(['commit', '-m', 'Benchmark fixture'], fixture.dir);
  return fixture;
}

async function cleanupFixture(fixture) {
  await Promise.allSettled([
    apiJson(`/v1/repos/${segment(fixture.owner)}/${segment(fixture.repo)}`, { method: 'DELETE' }),
    rm(fixture.dir, { recursive: true, force: true }),
  ]);
}

async function checkedGit(args, cwd) {
  const result = await sampleCommand('git', args, cwd);
  if (!result.ok) throw new Error(result.error || `git ${args.join(' ')} failed`);
}

function sampleCommand(command, args, cwd, extraEnv) {
  const started = performance.now();
  return new Promise((resolveSample) => {
    const child = spawn(command, args, {
      cwd,
      env: { ...process.env, ...extraEnv },
      stdio: ['ignore', 'pipe', 'pipe'],
    });
    const chunks = [];
    child.stdout.on('data', (chunk) => chunks.push(chunk));
    child.stderr.on('data', (chunk) => chunks.push(chunk));
    const timer = setTimeout(() => child.kill('SIGKILL'), timeoutMs);
    child.on('error', (error) => {
      clearTimeout(timer);
      resolveSample(sample(false, started, null, 0, error.message));
    });
    child.on('close', (code, signal) => {
      clearTimeout(timer);
      const bytes = chunks.reduce((total, chunk) => total + chunk.length, 0);
      const error = code === 0 ? null : Buffer.concat(chunks).toString('utf8').slice(-1000) || String(signal);
      resolveSample(sample(code === 0, started, code, bytes, error));
    });
  });
}

async function apiJson(path, options = {}) {
  const headers = {
    accept: 'application/json',
    authorization: `Bearer ${token}`,
  };
  if (options.body) headers['content-type'] = 'application/json';
  const response = await fetch(`${apiUrl}${path}`, {
    method: options.method || 'GET',
    headers,
    body: options.body ? JSON.stringify(options.body) : undefined,
    signal: AbortSignal.timeout(timeoutMs),
  });
  const text = await response.text();
  if (!response.ok) throw new Error(`${options.method || 'GET'} ${path}: HTTP ${response.status} ${text.slice(0, 300)}`);
  return text ? JSON.parse(text) : null;
}

function gitAuthEnv(destination, bearerToken) {
  const index = Number.parseInt(process.env.GIT_CONFIG_COUNT || '0', 10) || 0;
  return {
    GIT_CONFIG_COUNT: String(index + 1),
    [`GIT_CONFIG_KEY_${index}`]: `http.${destination}.extraHeader`,
    [`GIT_CONFIG_VALUE_${index}`]: `Authorization: Bearer ${bearerToken}`,
  };
}

function sample(ok, started, status, bytes, error) {
  return { ok, durationMs: performance.now() - started, status, bytes, error };
}

function summarize(values) {
  const durations = values.map((value) => value.durationMs).sort((a, b) => a - b);
  return {
    count: values.length,
    ok: values.filter((value) => value.ok).length,
    meanMs: round(durations.reduce((sum, value) => sum + value, 0) / durations.length),
    p50Ms: percentile(durations, 0.5),
    p95Ms: percentile(durations, 0.95),
    bytes: values.reduce((sum, value) => sum + value.bytes, 0),
  };
}

function percentile(values, point) {
  return round(values[Math.max(0, Math.ceil(values.length * point) - 1)] || 0);
}

function markdown(report) {
  const rows = report.cases
    .map((entry) => `| ${entry.name} | ${entry.ok ? 'yes' : 'no'} | ${entry.sequential.meanMs} | ${entry.sequential.p95Ms} |`)
    .join('\n');
  return `# Scope benchmark\n\nGenerated: ${report.generatedAt}\n\n| Case | OK | Mean ms | p95 ms |\n|---|---:|---:|---:|\n${rows}\n`;
}

async function expectReady() {
  const response = await fetch(`${apiUrl}/readyz`, { signal: AbortSignal.timeout(timeoutMs) });
  if (!response.ok) throw new Error(`API is not ready at ${apiUrl}`);
}

function positiveInt(name, fallback) {
  const value = Number.parseInt(process.env[name] || String(fallback), 10);
  if (!Number.isInteger(value) || value < 1) throw new Error(`${name} must be positive`);
  return value;
}

function normalizeHandle(value) {
  return value.toLowerCase().replace(/[^a-z0-9_-]+/g, '-').replace(/^-|-$/g, '') || 'dev';
}

function segment(value) {
  return encodeURIComponent(value);
}

function round(value) {
  return Math.round(value * 100) / 100;
}

function message(error) {
  return error instanceof Error ? error.message : String(error);
}

