  nav {
    justify-content: flex-start;
  }

  main {
    padding: 34px 18px 60px;
  }

  h1 {
    font-size: 44px;
  }

  .flow-row {
    grid-template-columns: 1fr;
    gap: 6px;
  }

  .matrix {
    display: block;
    overflow-x: auto;
    white-space: normal;
  }
}

