    48	fn parse_request_git_remote(
    49	    api_url: &str,
    50	    remote_name: &str,
    51	    remote_url: &str,
    52	) -> anyhow::Result<RequestRemoteTarget> {
    53	    let api = Url::parse(api_url).context("parse Scope API URL")?;
    54	    let remote = Url::parse(remote_url).context("parse Scope Git remote URL")?;
    55	
    56	    if api.scheme() != remote.scheme()
    57	        || api.host_str() != remote.host_str()
    58	        || api.port_or_known_default() != remote.port_or_known_default()
    59	    {
    60	        bail!(
    61	            "Scope remote points at {}, but this CLI is configured for {}",
    62	            redacted_url(&remote),
    63	            api.as_str().trim_end_matches('/')
    64	        );
    65	    }
    66	    if remote.password().is_some() {
    67	        bail!("Scope Git remote URL cannot include a password");
    68	    }
    69	
    70	    let segments = remote
    71	        .path_segments()
    72	        .map(|segments| segments.collect::<Vec<_>>())
    73	        .unwrap_or_default();
    74	    if segments.len() != 4
    75	        || segments[0] != "git"
    76	        || (segments[1] != "permissioned" && segments[1] != "public")
    77	    {
    78	        bail!(
    79	            "Scope request remote must have path /git/public/owner/repo or /git/permissioned/owner/repo"
    80	        );
    81	    }
    82	
    83	    let owner = segments[2].trim();
    84	    let repo = segments[3].trim();
    85	    if owner.is_empty() || repo.is_empty() {
    86	        bail!("Scope request remote must include owner and repo");
    87	    }
    88	
    89	    Ok(RequestRemoteTarget {
    90	        remote: remote_name.to_string(),
    91	        public_url: git_url_for_mode(&remote, "public", owner, repo)?,
    92	        permissioned_url: git_url_for_mode(&remote, "permissioned", owner, repo)?,
    93	        owner: owner.to_string(),
    94	        repo: repo.to_string(),
    95	    })
    96	}
